sp_page.css:
/* 1. Target the main wrappers that sit above the page level */
#main-content, 
.v-content-wrapper, 
.body-wrapper {
    padding-left: 0 !important;
    padding-right: 0 !important;
    margin-left: 0 !important;
    margin-right: 0 !important;
    width: 100% !important;
    max-width: 100% !important;
}

/* 2. Flatten the internal Bootstrap layers */
.container, 
.container-fluid {
    width: 100% !important;
    max-width: 100% !important;
    padding-left: 0 !important;
    padding-right: 0 !important;
}

/* 3. Remove Row gutter margins which cause horizontal shifting */
.row {
    margin-left: 0 !important;
    margin-right: 0 !important;
}

/* 4. Ensure the column holding your widget is also flush */
.col-md-12, .col-xs-12 {
    padding-left: 0 !important;
    padding-right: 0 !important;
}
